#include <bits/stdc++.h>
#include <numeric>
#include <iterator>
#include <random>
using namespace std;
const long long MOD1 = 1000000007;
const long long MOD2 = 998244353;
typedef long long ll;
typedef pair<ll, ll> P;
const long long INF = 1e17;
template <typename T>
void input_arr(vector<T>& A, ll N) {
    for (ll i = 0; i < N; i++) {
        cin >> A[i];
    }
}
void input_arr(vector<P>& A, ll N) {
    for (ll i = 0; i < N; i++) {
        cin >> A[i].first >> A[i].second;
    }
}
ll power(ll N, ll M, ll p) {
    ll ans = 1;
    while (M > 0) {
        if (M & 1) ans = ans * N % p;
        N = N * N % p;
        M >>= 1;
    }
    return ans;
}
ll floor_sqrt(ll N) {
    ll ok = -1, ng = 1000000001;
    while (abs(ok - ng) > 1) {
        ll mid = (ok + ng) / 2;
        if (mid * mid <= N) ok = mid;
        else ng = mid;
    }
    return ok;
}
void solve() {
    string S; cin >> S;
    vector<string>A(9); input_arr(A, 9);
    ll num = (S == "Second"), sum = 0;
    ll px, py;
    if (S == "First") {
        px = 8; py = 4;
    }
    else {
        px = 0; py = 4;
    }
    vector<vector<bool>>C(9, vector<bool>(9, false));
    for (ll i = 0; i < 9; i++) {
        for (ll j = 0; j < 9; j++) {
            if (A[i][j] == '#') C[i][j] = true;
        }
    }
    string T = "First";
    while (sum < 150) {
        if (S != T) {
            ll t; cin >> t;
            if (t == 0) {
                ll x; cin >> x;
            }
            else {
                ll x, y; cin >> x >> y;
            }
            num = 1 - num;
        }
        else {
            srand((unsigned int)time(NULL));
            cout << 0 << ' ';
            ll dx[4] = {0, 1, 0, -1};
            ll dy[4] = {-1, 0, 1, 0};
            vector<P>N;
            vector<ll>B;
            for (ll k = 0; k < 4; k++) {
                if (px + dx[k] < 0 || px + dx[k] >= 9) continue;
                if (py + dy[k] < 0 || py + dy[k] >= 9) continue;
                B.push_back(k);
                ll number = -1, pos = 1;
                while (0 <= px + dx[k] * pos && px + dx[k] * pos < 9 && 0 <= py + dy[k] * pos && py + dy[k] * pos < 9) {
                    if (C[px + dx[k] * pos][py + dy[k] * pos]) {
                        number = pos;
                        break;
                    }
                    pos++;
                }
                N.emplace_back(k, number);
            }
            if (N.empty()) {
                ll n = (ll)B.size();
                ll p = B[rand() % n];
                px += dx[p];
                py += dy[p];
                cout << B[rand() % n] << endl;
            }
            else {
                ll s = 0;
                for (ll i = 0; i < N.size(); i++) {
                    if (N[i].second != -1) s += N[i].second;
                }
                vector<ll>D;
                for (ll i = 0; i < N.size(); i++) {
                    if (N[i].second == -1) continue;
                    for (ll j = 0; j < (s - N[i].second); j++) {
                        D.push_back(N[i].first);
                    }
                }
                random_device seed_gen;
                mt19937 engine(seed_gen());
                shuffle(D.begin(), D.end(), engine);
                ll p = D[rand() % (ll)D.size()];
                px += dx[p];
                py += dy[p];
                if (C[px][py]) C[px][py] = false;
                cout << D[rand() % (ll)D.size()] << endl;
            }
        }
        if (T == "First") {
            T = "Second";
        }
        else {
            T = "First";
        }
        sum++;
    }
}
int main() {
    ll T=1;//cin>>T;
    while(T--)solve();
}
